	path_dirs = malloc(capacity * sizeof(char *));
	if (path_dirs == NULL)
		unix_error("malloc error");

	path_copy = strdup(pathstr);
	if (path_copy == NULL)
		unix_error("strdup error");

	path_count = 0;
	token = strtok_r(path_copy, ":", &saveptr);
	while (true) {
		if (path_count >= capacity - 1) {
			capacity *= 2;
			path_dirs = realloc(path_dirs, capacity * sizeof(char *));
			if (path_dirs == NULL)
				unix_error("realloc error");
		}
		/*
		 * Empty token means current directory ("").
		 * If the path starts with ':', ends with ':', or has "::",
